echo '=== configure redis ==='
cp -a /etc/redis.conf "/etc/redis.conf.bak.$(date +%Y%m%d_%H%M%S)"

# CentOS7 redis 3.2 conf tweaks via sed
sed -i 's/^bind .*/bind 127.0.0.1/' /etc/redis.conf
sed -i 's/^protected-mode .*/protected-mode yes/' /etc/redis.conf
sed -i 's/^port .*/port 6379/' /etc/redis.conf
sed -i 's/^tcp-keepalive .*/tcp-keepalive 60/' /etc/redis.conf
sed -i 's/^# maxmemory <bytes>/maxmemory 512mb/' /etc/redis.conf
sed -i 's/^maxmemory .*/maxmemory 512mb/' /etc/redis.conf
# policy line is commented by default
if grep -q '^maxmemory-policy ' /etc/redis.conf; then
  sed -i 's/^maxmemory-policy .*/maxmemory-policy allkeys-lru/' /etc/redis.conf
else
  sed -i 's/^# maxmemory-policy .*/maxmemory-policy allkeys-lru/' /etc/redis.conf
fi
# if still missing, append
grep -q '^maxmemory ' /etc/redis.conf || echo 'maxmemory 512mb' >> /etc/redis.conf
grep -q '^maxmemory-policy ' /etc/redis.conf || echo 'maxmemory-policy allkeys-lru' >> /etc/redis.conf

