def ssh(host, cmd, timeout=90):
    c = paramiko.SSHClient()
    c.set_missing_host_key_policy(paramiko.AutoAddPolicy())
    c.connect(host, username="root", password=ROOT_PW, timeout=20, allow_agent=False, look_for_keys=False)
